module RefModule(output reg [7:0] out, input [7:0] in, input ld,rshct,clk,reset);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk, posedge reset or posedge dbg_halt)
begin
    if(reset)
        out <= 0;
    else if(ld)
        out <= in;
    else if(rshct)
        out <= out >> 1;
end
endmodule
